sql:
SELECT u.full_name, r.recommendation
FROM users u
LEFT JOIN recommendations r ON u.user_id = r.user_id;

SELECT u.full_name, u.email, u.date_of_birth
FROM users u
WHERE (strftime('%Y', 'now') - strftime('%Y', u.date_of_birth)) > (
  SELECT AVG(strftime('%Y', 'now') - strftime('%Y', u2.date_of_birth))
  FROM users u2
);

SELECT COUNT(*)
FROM feedback
WHERE user_id = (SELECT user_id FROM users WHERE full_name = 'Alice Johnson');

SELECT COUNT(DISTINCT user_id)
FROM user_goals
WHERE user_id NOT IN (
  SELECT user_id
  FROM feedback
);

SELECT COUNT(*) AS total_users
FROM user_roles
WHERE role_id = 1;

external_knowledge:
- "identities" refers to the users' full names;
- "inner weights" metaphorically represent the users' average weight over their recorded measurements;
- "travelers" refers to users in the database;
- "whispers they've overheard in their journeys" metaphorically represents the messages in the notifications the users have received.

- "beacon lights" metaphorically refers to roles that stand out and are easily identifiable;
- "feedback storms" is a metaphor for a high volume of feedback;
- "glowing reviews" metaphorically refers to positive feedback or feedback in general.

sql:
SELECT user_id, full_name 
FROM users
WHERE user_id NOT IN (
    SELECT user_id 
    FROM feedback
);

SELECT COUNT(DISTINCT user_id) AS TotalFeedbackUsers
FROM feedback
WHERE comments IS NOT NULL AND comments <> '';

external_knowledge:
- 'Slimming targets' refer to the goal weights set by the users; 
- 'Trying to slim down' indicates a weight loss goal type; 
- 'Reached their goals' means the current weight is less than or equal to the target weight.

sql:
SELECT AVG(goal_value)
FROM user_goals
WHERE goal_type = 'Increase Weight';
